func (a *adapter) LoadLineagesByCustomer(ctx context.Context, input lineage.LoadLineagesByCustomerInput) ([]lineage.Lineage, error) {
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, tx *adapter) ([]lineage.Lineage, error) {
		lineages, err := tx.db.CreditRealizationLineage.Query().
			Where(creditrealizationlineage.Namespace(input.Namespace), creditrealizationlineage.CustomerIDEQ(input.CustomerID), creditrealizationlineage.CurrencyEQ(input.Currency)).
			WithSegments(func(q *entdb.CreditRealizationLineageSegmentQuery) {
				q.Where(creditrealizationlineagesegment.ClosedAtIsNil()).Order(creditrealizationlineagesegment.ByCreatedAt())
			}).
			Order(creditrealizationlineage.ByCreatedAt()).All(ctx)
		if err != nil { return nil, err }
		return lo.Map(lineages, mapLineage), nil
	})
}

return transaction.RunWithNoValue(ctx, s.adapter, func(ctx context.Context) error {
	lineages, err := s.adapter.LockCorrectionLineages(ctx, input.Namespace, correctionOrder)
	if err != nil { return fmt.Errorf("lock lineages for correction persistence: %w", err) }
	now := clock.Now().Truncate(time.Microsecond)
	for _, realizationID := range correctionOrder {
		entry := lineagesByRealizationID[realizationID]
		remaining := correctionAmountsByRealizationID[realizationID]
		for _, segment := range lineage.SortCorrectionPersistSegments(entry.Segments) {
			if !remaining.IsPositive() { break }
			consumed := lineage.MinDecimal(segment.Amount, remaining)
			if err := s.adapter.CloseSegment(ctx, segment.ID, now); err != nil { return err }
			if rem := segment.Amount.Sub(consumed); rem.IsPositive() {
				_ = s.adapter.CreateSegment(ctx, lineage.CreateSegmentInput{LineageID: segment.LineageID, Amount: rem, State: segment.State, BackingTransactionGroupID: segment.BackingTransactionGroupID})
			}
			remaining = remaining.Sub(consumed)
		}
		if remaining.IsPositive() { return fmt.Errorf("correction amount %s exceeds active lineage coverage for realization %s", remaining.String(), realizationID) }
	}
	return nil
})
